.bt-input-multi-options__wrapper {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
}

.bt-input-multi-options__label-row {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
}

.bt-input-multi-options__label {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  letter-spacing: 0;
}

.bt-input-multi-options--error .bt-input-multi-options__label {
  color: var(--text-error);
}

.bt-input-multi-options--disabled .bt-input-multi-options__label {
  color: var(--text-primary);
}

.bt-input-multi-options__required {
  color: var(--text-error);
}

.bt-input-multi-options__group {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-sm);
  align-items: center;
}

.bt-input-multi-options__helper {
  display: flex;
  gap: var(--space-xs);
  align-items: center;
}

.bt-input-multi-options__helper-text {
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  letter-spacing: 0;
}

.bt-input-multi-options__helper-text--error {
  color: var(--text-error);
}

/**
 * BTInputMultiOptions — labeled checkbox group / multi-select (Figma node 859-2091).
 *
 * A flex-wrap row of BTCheckbox items with a title label above and
 * optional validation / helper text below.
 *
 * @example
 * // Basic
 * const [selected, setSelected] = useState<string[]>([]);
 * const opts = [
 *   { value: 'a', label: 'Option A' },
 *   { value: 'b', label: 'Option B', subtext: 'Helper text' },
 *   { value: 'c', label: 'Disabled', disabled: true },
 * ];
 * <BTInputMultiOptions label="Pilih opsi" items={opts} value={selected} onChange={setSelected} />
 *
 * @example
 * // Required + validator
 * const ref = useRef<BTInputMultiOptionsHandle>(null);
 * <BTInputMultiOptions
 *   label="Kategori"
 *   items={opts}
 *   value={selected}
 *   onChange={setSelected}
 *   required
 *   validator={v => v.length ? null : 'Pilih minimal satu opsi'}
 *   ref={ref}
 * />
 * // Trigger validation: ref.current?.validate()
 */
import React from 'react';
import './BTInputMultiOptions.css';
import type {
  BTInputMultiOptionsProps,
  BTInputMultiOptionsHandle,
} from './BTInputMultiOptions.types.js';
import { BTCheckbox } from './index.js';

export const BTInputMultiOptions = React.forwardRef<
  BTInputMultiOptionsHandle,
  BTInputMultiOptionsProps
>(function BTInputMultiOptions(
  {
    value,
    onChange,
    label,
    required = false,
    items,
    disabled = false,
    errorText,
    helperText,
    validator,
    className,
  },
  ref,
) {
  const [errorInternal, setErrorInternal] = React.useState<string | null>(null);
  const activeError = errorText ?? errorInternal ?? null;
  const hasError = !!activeError;

  React.useImperativeHandle(
    ref,
    () => ({
      validate() {
        if (!validator) return true;
        const result = validator(value ?? []);
        setErrorInternal(result ?? null);
        return result === null;
      },
    }),
    [validator, value],
  );

  function handleToggle(itemValue: unknown, checked: boolean) {
    if (disabled) return;
    setErrorInternal(null);
    const current = (value ?? []) as unknown[];
    const next = checked
      ? [...current, itemValue]
      : current.filter((v) => v !== itemValue);
    onChange?.(next as Parameters<typeof onChange>[0]);
  }

  const wrapperClass = [
    'bt-input-multi-options__wrapper',
    hasError && !disabled && 'bt-input-multi-options--error',
    disabled && 'bt-input-multi-options--disabled',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <div className={wrapperClass}>
      {/* Label row */}
      {label && (
        <div className="bt-input-multi-options__label-row">
          <span className="bt-input-multi-options__label">
            {label}
            {required && (
              <span className="bt-input-multi-options__required">*</span>
            )}
          </span>
        </div>
      )}

      {/* Checkbox group */}
      <div
        className="bt-input-multi-options__group"
        role="group"
        aria-required={required || undefined}
        aria-disabled={disabled || undefined}
        aria-invalid={(hasError && !disabled) || undefined}
      >
        {items.map((item) => (
          <BTCheckbox
            key={String(item.value)}
            checked={(value ?? []).includes(item.value)}
            label={item.label}
            subtext={item.subtext}
            disabled={disabled || !!item.disabled}
            error={hasError && !disabled}
            onChange={(checked) => handleToggle(item.value, checked)}
          />
        ))}
      </div>

      {/* Helper / error text — error suppressed when disabled */}
      {((!disabled && activeError) || helperText) && (
        <div className="bt-input-multi-options__helper">
          <span
            className={[
              'bt-input-multi-options__helper-text',
              hasError && !disabled &&
                'bt-input-multi-options__helper-text--error',
            ]
              .filter(Boolean)
              .join(' ')}
          >
            {(!disabled && activeError) || helperText}
          </span>
        </div>
      )}
    </div>
  );
});

BTInputMultiOptions.displayName = 'BTInputMultiOptions';

/**
 * BTInputMultiOptions — labeled checkbox group types.
 *
 * Figma node 859-2091.
 */

/** A single option in the checkbox group. */
export interface BTInputMultiOptionsItem<T = string> {
  /** Unique value added to / removed from the value array on toggle. */
  value: T;
  /** Visible label beside the checkbox. */
  label?: string;
  /** Secondary helper text below the label. */
  subtext?: string;
  /** Disables only this option while the group remains active. */
  disabled?: boolean;
}

export interface BTInputMultiOptionsProps<T = string> {
  /** Currently selected values. Defaults to empty array. */
  value?: T[];
  /** Called when the user toggles an option. */
  onChange?: (value: T[]) => void;
  /** Group label shown above the checkbox list. */
  label?: string;
  /** Shows a red `*` after the label when true. */
  required?: boolean;
  /** Checkbox options to render. */
  items: BTInputMultiOptionsItem<T>[];
  /** Disables the entire group. */
  disabled?: boolean;
  /**
   * External error message. When set, all checkboxes show the error border
   * and the text is displayed below the group in error colour.
   * Overrides any internal validator error.
   */
  errorText?: string;
  /** Helper text shown below the group in the default state. */
  helperText?: string;
  /**
   * Validation function called by `validate()` (via ref handle).
   * Return an error string or null.
   */
  validator?: (value: T[]) => string | null;
  /** Additional CSS class names. */
  className?: string;
}

export interface BTInputMultiOptionsHandle {
  /** Runs the validator and shows the error message. Returns true when valid. */
  validate(): boolean;
}
